Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word:

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <unordered_map>
#include <algorithm>

int main() {
    std::string filename, search_word;
    std::cout << "Enter filename: ";
    std::cin >> filename;
    std::cout << "Enter search word: ";
    std::cin >> search_word;

    std::unordered_map<std::string, int> word_counts; // unordered map to store word counts
    std::vector<std::string> lines; // vector to store file lines

    std::ifstream file(filename); // open input file
    if (!file.is_open()) { // check if file is open
        std::cerr << "Error: Could not open file " << filename << "." << std::endl;
        return 1;
    }

    std::string line;
    while (std::getline(file, line)) { // read each line of the file
        std::size_t pos = 0;
        std::string token;
        std::stringstream stream(line);
        while (std::getline(stream, token, ' ', &pos)) { // tokenize line into words
            lines.push_back(token); // add word to vector of lines
            auto it = word_counts.find(token); // check if word already exists in word counts map
            if (it != word_counts.end() && token == search_word) { // if word exists and is the search word, increment count
                it->second++;
            } else if (token == search_word) { // if word is the search word and doesn't exist yet, add it to map with count 1
                word_counts[token] = 1;
            }
        }
    }

    file.close(); // close input file

    std::cout << "Number of occurrences of \"" << search_word << "\" in \"" << filename << "\":" << std::endl;
    for (auto& it : word_counts) { // print all words and their counts, including search word if found
        if (it.second > 0 && (it.first == search_word || std::find(lines.begin(), lines.end(), it.first) != lines.end())) { // check if word is the search word or is in the list of lines read from file
            std::cout << it.first << " (" << it.second << ")" << std::endl;
        }
    }

    return 0;
}
```

